        "valid": true,
        "roleType": 1,
        "roleName": "司机1111"
    }]

请看下面的代码示例，该方法根据传入的数组对`roleType`进行分组，并返回分组后的结果。代码中使用了ES6中的`Map`数据结构和`reduce`方法来实现分组操作：

```
function groupByRoleType(arr) {
  const map = new Map();
  arr.reduce((_, obj) => {
    if (!map.has(obj.roleType)) {
      map.set(obj.roleType, []);
    }
    map.get(obj.roleType).push(obj);
  }, null);
  return Array.from(map, ([roleType, group]) => ({ roleType, group }));
}
```

将上面的方法运行在下面的数据中：

```
const data = [{
    "imgUrl": "1234",
    "name": "路鑫111",
    "links": {
        "h5": "1234"
    },
